$ErrorActionPreference = "Stop"

$Root = Split-Path -Parent $MyInvocation.MyCommand.Path
$EnvFile = ".env.mimo.local"
$ClaudeArgs = $args
if ($ClaudeArgs.Count -gt 0) {
    $firstArg = [string]$ClaudeArgs[0]
    if ($firstArg -match '(?i)(^|[\/])claude(\.exe)?$' -or $firstArg -match '(?i)(^|[\/])cli\.js$') {
        $ClaudeArgs = @($ClaudeArgs | Select-Object -Skip 1)
    }
}

$ConfigPath = Join-Path $Root $EnvFile
$PreferredClaudeCmd = "E:\CC-test\npm-global\claude.cmd"
$FallbackClaudeCmd = Join-Path $Root "node_modules\.bin\claude.cmd"

if (Test-Path -LiteralPath $PreferredClaudeCmd) {
    $ClaudeCmd = $PreferredClaudeCmd
} elseif (Test-Path -LiteralPath $FallbackClaudeCmd) {
    $ClaudeCmd = $FallbackClaudeCmd
} else {
    throw "Claude Code CLI was not found. Install with: npm install -g @anthropic-ai/claude-code --prefix E:\CC-test\npm-global --cache E:\CC-test\.npm-cache"
}

if (-not (Test-Path -LiteralPath $ConfigPath)) {
    throw "Missing $ConfigPath"
}

Get-Content -LiteralPath $ConfigPath | ForEach-Object {
    $line = $_.Trim()
    if (-not $line -or $line.StartsWith("#")) { return }
    $parts = $line.Split("=", 2)
    if ($parts.Count -ne 2) { return }
    $name = $parts[0].Trim()
    $value = $parts[1].Trim()
    if (($value.StartsWith('"') -and $value.EndsWith('"')) -or ($value.StartsWith("'") -and $value.EndsWith("'"))) {
        $value = $value.Substring(1, $value.Length - 2)
    }
    [Environment]::SetEnvironmentVariable($name, $value, "Process")
}

if (-not $env:CLAUDE_CONFIG_DIR) {
    $env:CLAUDE_CONFIG_DIR = Join-Path $env:USERPROFILE ".claude"
}

$env:npm_config_cache = "E:\CC-test\.npm-cache"
$env:TERM = "xterm-256color"
$env:COLORTERM = "truecolor"
$env:CLAUDE_CODE_NATIVE_CURSOR = "1"
$env:CLAUDE_CODE_NO_FLICKER = "1"
$env:CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC = "1"
$env:DISABLE_TELEMETRY = "1"

& $ClaudeCmd @ClaudeArgs
exit $LASTEXITCODE

