#!/usr/bin/env node
const { spawn } = require('child_process');
const path = require('path');
const fs = require('fs');

const root = __dirname;
const envFile = '.env.mimo.local';
const configPath = path.join(root, envFile);

// Load env vars from config
if (fs.existsSync(configPath)) {
  const lines = fs.readFileSync(configPath, 'utf-8').split('\n');
  for (const raw of lines) {
    const line = raw.trim();
    if (!line || line.startsWith('#')) continue;
    const idx = line.indexOf('=');
    if (idx < 1) continue;
    const name = line.substring(0, idx).trim();
    let value = line.substring(idx + 1).trim();
    if ((value.startsWith('"') && value.endsWith('"')) ||
        (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }
    process.env[name] = value;
  }
}

// Set defaults
if (!process.env.CLAUDE_CONFIG_DIR) {
  process.env.CLAUDE_CONFIG_DIR = path.join(process.env.USERPROFILE || '', '.claude');
}
process.env.npm_config_cache = 'E:\\CC-test\\.npm-cache';
process.env.TERM = 'xterm-256color';
process.env.COLORTERM = 'truecolor';
process.env.CLAUDE_CODE_NATIVE_CURSOR = '1';
process.env.CLAUDE_CODE_NO_FLICKER = '1';
process.env.CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC = '1';
process.env.DISABLE_TELEMETRY = '1';

// Find claude.cmd
const preferredCmd = 'E:\\CC-test\\npm-global\\claude.cmd';
const fallbackCmd = path.join(root, 'node_modules', '.bin', 'claude.cmd');

let claudeCmd;
if (fs.existsSync(preferredCmd)) {
  claudeCmd = preferredCmd;
} else if (fs.existsSync(fallbackCmd)) {
  claudeCmd = fallbackCmd;
} else {
  console.error('Claude Code CLI not found. Install with: npm install -g @anthropic-ai/claude-code --prefix E:\\CC-test\\npm-global --cache E:\\CC-test\\.npm-cache');
  process.exit(1);
}

// Filter args - skip claude.exe if passed as first arg
let args = process.argv.slice(2);
if (args.length > 0) {
  const first = args[0];
  if (/(?i)(^|[\/])claude(\.exe)?$/.test(first) || /(?i)(^|[\/])cli\.js$/.test(first)) {
    args = args.slice(1);
  }
}

// Spawn claude.cmd with shell:true on Windows
const child = spawn('cmd.exe', ['/c', claudeCmd, ...args], {
  stdio: 'inherit',
  env: process.env,
  shell: false
});

child.on('exit', (code) => {
  process.exit(code || 0);
});

child.on('error', (err) => {
  console.error('Failed to start Claude:', err.message);
  process.exit(1);
});

